#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    char text[] = "Merhaba Playground";

    printf("Metin: %s\n", text);
    printf("Uzunluk: %lu\n", strlen(text));

    // Buyuk/kucuk harf
    char upper[20];
    strcpy(upper, text);
    for (int i = 0; upper[i]; i++) {
        upper[i] = toupper(upper[i]);
    }
    printf("\nBuyuk harf: %s\n", upper);

    // Karsilastirma
    char a[] = "elma";
    char b[] = "armut";
    int cmp = strcmp(a, b);
    printf("\n'%s' ile '%s' karsilastirma: %d\n", a, b, cmp);

    // Birlestirme
    char greeting[30] = "Merhaba, ";
    strcat(greeting, "Dunya!");
    printf("\nBirlestirilmis: %s\n", greeting);

    // Arama
    char* found = strstr(text, "Play");
    if (found != NULL) {
        printf("\n'Play' bulundu: %s\n", found);
    }

    // Kopyalama
    char copy[20];
    strcpy(copy, text);
    printf("\nKopya: %s\n", copy);

    return 0;
}
